#include<bits/stdc++.h>
using namespace std;
long long f[7010][7010],a[7010];
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long n;
        scanf("%lld",&n);
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld",&a[i]);
        }
        for(long long r=2;r<=n;r++)
        {
            deque<long long> q;
            q.push_back(r-1);
            f[r][r-1]=a[r-1];
            long long k=r;
            for(long long l=r-2;l>=1;l--)
            {
                while(f[k-1][l]>f[r][k]&&l<k)
                {
                    k--;
                }
                f[r][l]=f[k][l]+a[k];
                while(!q.empty()&&k<=q.front())
                {
                    q.pop_front();
                }
                if(!q.empty())
                {
                    f[r][l]=min(f[r][l],f[r][q.front()+1]+a[q.front()]);
                }
                while(!q.empty()&&f[r][q.back()+1]+a[q.back()]>=f[r][l+1]+a[l])
                {
                    q.pop_back();
                }
                q.push_back(l);
            }
        }
        printf("%lld\n",f[n][1]);
    }
    return 0;
}
